def get_lexer_for_response(response: Response) -> str:
    """Return a Pygments lexer name appropriate for the response's Content-Type.

    If no appropriate lexer is found, return an empty string.
    """
    content_type = response.headers.get("Content-Type")
    if content_type is not None:
        mime_type, _, _ = content_type.partition(";")
        try:
            return typing.cast(
                str, pygments.lexers.get_lexer_for_mimetype(mime_type.strip()).name
            )
        except pygments.util.ClassNotFound:  # pragma: no cover
            pass
    return ""  # pragma: no cover


def format_request_headers(request: httpcore.Request, http2: bool = False) -> str:
    """Format an HTTP request's start line and headers into a printable string.

    The http2 flag will cause header names to be lowercased to reflect HTTP/2 style.
    """
    version = "HTTP/2" if http2 else "HTTP/1.1"
    # request.headers can be a sequence of (name, value) tuples where each is bytes or str.
    headers = [
        (name.lower() if http2 else name, value) for name, value in request.headers
    ]
    method = request.method.decode("ascii") if isinstance(request.method, (bytes, bytearray)) else str(request.method)
    # request.url.target may be bytes for httpcore; handle both
    target = (
        request.url.target.decode("ascii")
        if isinstance(request.url.target, (bytes, bytearray))
        else str(request.url.target)
    )
    lines = [f"{method} {target} {version}"]
    for name, value in headers:
        if isinstance(name, (bytes, bytearray)):
            name_text = name.decode("latin-1")
        else:
            name_text = str(name)
        if isinstance(value, (bytes, bytearray)):
            value_text = value.decode("latin-1")
        else:
            value_text = str(value)
        lines.append(f"{name_text}: {value_text}")
    return "\n".join(lines)


def format_response_headers(response: Response, http2: bool = False) -> str:
    """Format an HTTP response's status line and headers into a printable string.

    The http2 flag will change the version reported in the status line.
    """
    version = "HTTP/2" if http2 else "HTTP/1.1"
    status = getattr(response, "status_code", None) or getattr(response, "status", None)
    # Obtain a reason phrase if available, otherwise look up from codes mapping.
    reason = getattr(response, "reason_phrase", None) or codes.get(int(status), "")
    lines = [f"{version} {status} {reason}"]
    # response.headers is mapping-like; iterate items for stable ordering
    try:
        items = response.headers.items()
    except Exception:
        # Fallback: if headers are stored differently
        items = list(response.headers)  # type: ignore
    for name, value in items:
        name_text = str(name)
        value_text = str(value)
        lines.append(f"{name_text}: {value_text}")
    return "\n".join(lines)


def print_request_headers(request: httpcore.Request, http2: bool = False, console: typing.Optional[rich.console.Console] = None) -> None:
    """Print formatted request headers to the console using Rich."""
    console = console or rich.console.Console()
    console.print(rich.markup.escape(format_request_headers(request, http2=http2)))


def print_response_headers(response: Response, http2: bool = False, console: typing.Optional[rich.console.Console] = None) -> None:
    """Print formatted response headers to the console using Rich."""
    console = console or rich.console.Console()
    console.print(rich.markup.escape(format_response_headers(response, http2=http2)))


def print_response(response: Response, verbose: bool = False, http2: bool = False, console: typing.Optional[rich.console.Console] = None) -> None:
    """Print a response's status, headers (optionally), and body with syntax highlighting.

    If verbose is True, headers (request and response) will be included. The http2 flag
    affects how HTTP versions and header names are presented.
    """
    console = console or rich.console.Console()
    # Print status and headers
    console.print(f"[bold]HTTP {response.status_code} {codes.get(int(response.status_code), '')}[/bold]")
    if verbose:
        print_response_headers(response, http2=http2, console=console)
        console.print()

    # Get response body as text if possible
    body_text = ""
    try:
        # Prefer text attribute if available (decodes using response encoding)
        if hasattr(response, "text"):
            body_text = getattr(response, "text")
            if body_text is None:
                body_text = ""
        else:
            content = getattr(response, "content", b"")
            if isinstance(content, (bytes, bytearray)):
                body_text = content.decode("utf-8", errors="replace")
            else:
                body_text = str(content)
    except Exception:
        body_text = ""

    lexer_name = get_lexer_for_response(response)
    if lexer_name:
        # rich.syntax accepts a Pygments lexer name in the "language" parameter
        try:
            syntax = rich.syntax.Syntax(body_text, lexer_name.lower(), theme="monokai", word_wrap=True)
            console.print(syntax)
        except Exception:
            console.print(body_text)
    else:
        console.print(body_text)


def format_certificate(certificate: typing.Mapping[str, typing.Any]) -> str:
    """Format a TLS certificate mapping into a readable string.

    The certificate mapping is expected to contain common fields such as
    'subject', 'issuer', and 'not_before'/'not_after' where available.
    """
    parts = []
    if not certificate:
        return ""
    # Common certificate fields: dicts or sequences; handle gracefully
    subject = certificate.get("subject") or certificate.get("Subject")
    issuer = certificate.get("issuer") or certificate.get("Issuer")
    not_before = certificate.get("not_before") or certificate.get("notBefore")
    not_after = certificate.get("not_after") or certificate.get("notAfter")
    if subject:
        parts.append(f"Subject: {subject}")
    if issuer:
        parts.append(f"Issuer: {issuer}")
    if not_before:
        parts.append(f"Not Before: {not_before}")
    if not_after:
        parts.append(f"Not After: {not_after}")
    # Any remaining items dump as JSON for completeness
    extra = {k: v for k, v in certificate.items() if k not in ("subject", "issuer", "not_before", "not_before", "notAfter", "notBefore", "Subject", "Issuer")}
    if extra:
        try:
            parts.append("Extra: " + json.dumps(extra, default=str))
        except Exception:
            parts.append("Extra: <unprintable>")
    return "\n".join(parts)


def trace(client: Client, request: httpcore.Request) -> Response:
    """Send a request using the provided Client and return the Response.

    This function is a thin wrapper around Client.request that ensures any
    RequestError is converted into the module's RequestError for consistent handling.
    """
    try:
        return client.request(request)
    except RequestError:
        # propagate known RequestError instances unchanged
        raise
    except Exception as exc:
        # Wrap other exceptions for callers
        raise RequestError(str(exc)) from exc


def download_response(response: Response, file_path: str) -> str:
    """Save the response content to the given file path and return the path.

    Overwrites existing files. Raises RequestError on failure.
    """
    try:
        content = getattr(response, "content", None)
        # If response provides an iter_bytes generator, prefer streaming to avoid memory spikes.
        if content is None and hasattr(response, "iter_bytes"):
            with open(file_path, "wb") as f:
                for chunk in response.iter_bytes():
                    f.write(chunk)
        else:
            # content may be bytes or str; ensure bytes are written.
            if isinstance(content, str):
                content_bytes = content.encode("utf-8")
            elif isinstance(content, (bytes, bytearray)):
                content_bytes = bytes(content)
            else:
                # Fallback to getting raw content via .read if available
                if hasattr(response, "read"):
                    content_bytes = response.read()
                else:
                    content_bytes = b""
            with open(file_path, "wb") as f:
                f.write(content_bytes)
        return file_path
    except OSError as exc:
        raise RequestError(f"Failed to write response to {file_path}: {exc}") from exc
    except Exception as exc:
        raise RequestError(f"Failed to download response: {exc}") from exc


def validate_json(ctx: click.Context, param: click.Parameter, value: typing.Optional[str]) -> typing.Optional[typing.Any]:
    """Validate a JSON string provided as a CLI parameter.

    Returns the parsed JSON object if valid, otherwise raises a click.BadParameter.
    """
    if value is None:
        return None
    try:
        return json.loads(value)
    except json.JSONDecodeError as exc:
        raise click.BadParameter(f"Invalid JSON: {exc}") from exc


def validate_auth(ctx: click.Context, param: click.Parameter, value: typing.Optional[typing.Sequence[str]]) -> typing.Optional[typing.Tuple[str, str]]:
    """Validate authentication credentials provided as CLI parameters.

    Expects a sequence of two items: username and password. If the password is '-',
    a hidden prompt will be shown to collect the password interactively.
    """
    if value is None:
        return None
    # Ensure it's a sequence of length 2
    if not isinstance(value, (list, tuple)) or len(value) != 2:
        raise click.BadParameter("Auth must be provided as two values: USER PASS")
    user, password = value[0], value[1]
    if password == "-":
        password = click.prompt("Password", hide_input=True)
    return user, password


def handle_help(ctx: click.Context, param: click.Parameter, value: bool) -> None:
    """Handle --help flag by printing help text and exiting.

    This is intended to be used as a callback for Click options.
    """
    if not value or ctx.resilient_parsing:
        return
    print_help()
    ctx.exit()